1	//
2	// PCILeech FPGA.
3	//
4	// SystemVerilog Header File for PCILeech FPGA projects.
5	//
6	// (c) Ulf Frisk, 2019-2024
7	// Author: Ulf Frisk, pcileech@frizk.net
8	//
9	
10	`ifndef _pcileech_header_svh_
11	`define _pcileech_header_svh_
12	
13	`define _bs16(v)   {{v}[7:0], {v}[15:8]}
14	`define _bs32(v)   {{v}[7:0], {v}[15:8], {v}[23:16], {v}[31:24]}
15	
16	// ------------------------------------------------------------------------
17	// Interface connecting COM to FIFO module.
18	// ------------------------------------------------------------------------
19	interface IfComToFifo;
20	    wire [63:0]     com_dout;
21	    wire            com_dout_valid;
22	    wire [255:0]    com_din;
23	    wire            com_din_wr_en;
24	    wire            com_din_ready;
25	
26	    modport mp_com (
27	        output com_dout, com_dout_valid, com_din_ready,
28	        input com_din, com_din_wr_en
29	    );
30	
31	    modport mp_fifo (
32	        input com_dout, com_dout_valid, com_din_ready,
33	        output com_din, com_din_wr_en
34	    );
35	endinterface
36	
37	// ------------------------------------------------------------------------
38	// Interface connecting PCIe to PCIe CFG module.
39	// ------------------------------------------------------------------------
40	interface IfPCIeSignals;
41	    // ------------------------------------------------------------------------
42	    // VALUES FROM PCIe TO module.
43	    // ------------------------------------------------------------------------
